import plotly.graph_objects as go
import numpy as np
import pandas as pd

def plot_token_statistics(all_token, success_tokens, bin_size=500):
    """
    สร้างกราฟสถิติเปรียบเทียบระหว่าง All Tokens และ Success Tokens
    
    Parameters:
    - all_token (list): รายการความยาว Token ทั้งหมด
    - success_tokens (list): รายการความยาว Token ที่โจมตีสำเร็จ
    - bin_size (int): ช่วงความยาวที่ต้องการแบ่ง (เช่น 500)
    """
    
    # 1. กำหนดช่วง (Bins) โดยคำนวณจากค่าสูงสุดของข้อมูล
    max_val = max(max(all_token), max(success_tokens))
    bins = np.arange(0, max_val + bin_size + 1, bin_size)
    
    # 2. นับจำนวนในแต่ละช่วง
    all_counts, _ = np.histogram(all_token, bins=bins)
    success_counts, _ = np.histogram(success_tokens, bins=bins)
    
    # 3. เตรียมข้อมูลและคำนวณ % ความสำเร็จ
    labels = [f"{int(bins[i])}-{int(bins[i+1])}" for i in range(len(bins)-1)]
    
    percentages = []
    for s, a in zip(success_counts, all_counts):
        percentages.append((s / a * 100) if a > 0 else 0)
    
    # สร้าง DataFrame เพื่อความสะดวกในการจัดการข้อมูล
    df = pd.DataFrame({
        'range': labels,
        'all': all_counts,
        'success': success_counts,
        'pct': percentages
    })
    
    # กรองแสดงเฉพาะช่วงที่มีข้อมูล (All Tokens > 0)
    df = df[df['all'] > 0].reset_index(drop=True)

    # 4. สร้างกราฟ Interactive
    fig = go.Figure()

    # แท่ง All Tokens
    fig.add_trace(go.Bar(
        x=df['range'],
        y=df['all'],
        name='จำนวน Token ทั้งหมด',
        marker_color='lightblue',
        text=df['all'],
        textposition='outside'
    ))

    # แท่ง Success Tokens
    fig.add_trace(go.Bar(
        x=df['range'],
        y=df['success'],
        name='จำนวนที่สำเร็จ (Success)',
        marker_color='crimson',
        text=df['success'],
        textposition='inside'
    ))

    # เส้น % ความสำเร็จ (แกน Y ที่ 2)
    fig.add_trace(go.Scatter(
        x=df['range'],
        y=df['pct'],
        name='อัตราสำเร็จ (%)',
        yaxis='y2',
        mode='lines+markers+text',
        text=[f"{p:.1f}%" for p in df['pct']],
        textposition="top center",
        line=dict(color='gold', width=3),
        marker=dict(size=8)
    ))

    # 5. ปรับ Layout
    fig.update_layout(
        title=f'สถิติเปรียบเทียบ Token และอัตราการโจมตีสำเร็จ (แบ่งช่วงละ {bin_size} Token)',
        xaxis_title='ช่วงความยาวของ Token (Token Length Range)',
        yaxis_title='จำนวน (Count)',
        yaxis2=dict(
            title='อัตราความสำเร็จ (%)',
            overlaying='y',
            side='right',
            range=[0, max(df['pct']) * 1.2 if len(df['pct']) > 0 else 100] # ปรับ scale แกนขวา
        ),
        barmode='group',
        template='plotly_white',
        legend=dict(x=0.01, y=1.1, orientation='h'),
        hovermode='x unified'
    )

    return fig.show()


plot_token_statistics(all_token, success_tokens, bin_size=1000)